import Foundation

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func logUserInteraction(action: String, userId: String, additionalInfo: String? = nil) {
        let logMessage = "User Interaction: \(action), User ID: \(userId)"
        if let info = additionalInfo {
            print("\(logMessage), Additional Info: \(info)")
        } else {
            print(logMessage)
        }
    }
    
    func logAuthenticationFlow(userId: String, email: String, token: String, success: Bool) {
        let status = success ? "Success" : "Failure"
        NSLog("Authentication Flow: User ID: \(userId), Email: \(email), Token: \(token), Status: \(status)")
    }
    
    func logAPICall(endpoint: String, requestPayload: [String: Any], responsePayload: [String: Any]) {
        NSLog("API Call: Endpoint: \(endpoint), Request: \(requestPayload), Response: \(responsePayload)")
    }
    
    func logUserDataChange(userId: String, changedData: [String: Any]) {
        NSLog("User Data Change: User ID: \(userId), Changed Data: \(changedData)")
    }
    
    func logError(condition: String, error: Error) {
        NSLog("Error Condition: \(condition), Error: \(error.localizedDescription)")
    }
}

